1	package runner
2	
3	import (
4		"fmt"
5		"io"
6		"os"
7		"strings"
8		"sync"
9	
10		"github.com/an-lee/gh-sr/internal/autostart"
11		"github.com/an-lee/gh-sr/internal/config"
12		"github.com/an-lee/gh-sr/internal/host"
13	)
14	
15	type Manager struct {
16		GitHub *GitHubClient
17		// Out receives progress messages from runner operations. If nil, os.Stdout is used.
18		Out io.Writer
19	}
20	
21	func (m *Manager) out() io.Writer {
22		if m != nil && m.Out != nil {
23			return m.Out
24		}
25		return os.Stdout
26	}
27	
28	func NewManager(pat string) *Manager {
29		return &Manager{
30			GitHub: NewGitHubClient(pat),
31		}
32	}
33	
34	type RunnerStatus struct {
35		Instance string
36		Host     string
37		Repo     string // owner/repo for repo-scoped, "org:name" for org-scoped
38		Labels   string
39		Mode     string
40		Local    string // "running", "stopped", "not installed"
41		Remote   string // from GitHub API: "online", "offline", ""
42		Busy     bool
43	}
44	
45	func (m *Manager) Setup(h *host.Host, rc config.RunnerConfig) error {
46		return m.setupNative(h, rc)
47	}
48	
49	// NeedsSetup checks whether a runner requires setup before it can start.
50	// Checks if any instance is missing the .runner config file.
51	func (m *Manager) NeedsSetup(h *host.Host, rc config.RunnerConfig) bool {
52		for _, name := range rc.InstanceNames() {
53			ok, _ := NativeRunnerConfigPresent(h, name)
54			if !ok {
55				return true
56			}
57		}
58		return false
59	}
60	
61	// EnsureSetup runs setup only if the runner is not already installed.
62	func (m *Manager) EnsureSetup(h *host.Host, rc config.RunnerConfig) error {
63		if !m.NeedsSetup(h, rc) {
64			return nil
65		}
66		fmt.Fprintf(m.out(), "  %s: not yet set up, running setup...\n", rc.Name)
67		return m.Setup(h, rc)
68	}
69	
70	func (m *Manager) Start(h *host.Host, rc config.RunnerConfig) error {
71		for _, name := range rc.InstanceNames() {
72			kind, derr := autostart.Detect(h, name)
73			if derr != nil {
74				return fmt.Errorf("starting %s: %w", name, derr)
75			}
76			var err error
77			if kind != autostart.KindNone {
78				err = autostart.Start(h, name)
79			} else {
80				err = m.startNative(h, rc, name)
81			}
82			if err != nil {
83				return fmt.Errorf("starting %s: %w", name, err)
84			}
85		}
86		return nil
87	}
88	
89	func (m *Manager) Stop(h *host.Host, rc config.RunnerConfig) error {
90		for _, name := range rc.InstanceNames() {
91			kind, derr := autostart.Detect(h, name)
92			if derr != nil {
93				return fmt.Errorf("stopping %s: %w", name, derr)
94			}
95			var err error
96			if kind != autostart.KindNone {
97				err = autostart.Stop(h, name)
98			} else {
99				err = m.stopNative(h, name)
100			}
101			if err != nil {
102				return fmt.Errorf("stopping %s: %w", name, err)
103			}
104		}
105		return nil
106	}
107	
108	func (m *Manager) Remove(h *host.Host, rc config.RunnerConfig) error {
109		for _, name := range rc.InstanceNames() {
110			if err := m.removeNative(h, rc, name); err != nil {
111				return fmt.Errorf("removing %s: %w", name, err)
112			}
113		}
114		return nil
115	}
116	
117	func (m *Manager) Status(h *host.Host, rc config.RunnerConfig) ([]RunnerStatus, error) {
118		var statuses []RunnerStatus
119	
120		for _, name := range rc.InstanceNames() {
121			repoDisplay := rc.Repo
122			if rc.Org != "" {
123				repoDisplay = "org:" + rc.Org
124			}
125			s := RunnerStatus{
126				Instance: name,
127				Host:     rc.Host,
128				Repo:     repoDisplay,
129				Labels:   strings.Join(rc.EffectiveLabels(h.OS, h.Arch), ", "),
130				Mode:     "native",
131			}
132	
133			s.Local = m.statusNative(h, name)
134			statuses = append(statuses, s)
135		}
136	
137		return statuses, nil
138	}
139	
140	func (m *Manager) Logs(h *host.Host, rc config.RunnerConfig, instanceName string) (string, error) {
141		return m.logsNative(h, instanceName)
142	}
143	
144	// expectedGitHubRunnerOS returns the expected OS label for GitHub API based on host OS.
145	func expectedGitHubRunnerOS(hostOS string) string {
146		switch hostOS {
147		case "windows":
148			return "Windows"
149		case "linux":
150			return "Linux"
151		case "darwin":
152			return "macOS"
153		default:
154			return ""
155		}
156	}
157	
158	func (m *Manager) EnrichWithGitHubStatus(statuses []RunnerStatus, cfg *config.Config) {
159		type scopeKey struct{ scope, target string }
160		keys := make(map[scopeKey]bool)
161		for _, r := range cfg.Runners {
162			keys[scopeKey{r.Scope(), r.ScopeTarget()}] = true
163		}
164	
165		scopeRunners := make(map[scopeKey][]GitHubRunner, len(keys))
166		var mu sync.Mutex
167		var wg sync.WaitGroup
168		for key := range keys {
169			wg.Add(1)
170			go func(k scopeKey) {
171				defer wg.Done()
172				runners, err := m.GitHub.ListRunnersScoped(k.scope, k.target)
173				if err != nil {
174					return
175				}
176				mu.Lock()
177				scopeRunners[k] = runners
178				mu.Unlock()
179			}(key)
180		}
181		wg.Wait()
182	
183		rcByInstance := make(map[string]*config.RunnerConfig)
184		for i := range cfg.Runners {
185			rc := &cfg.Runners[i]
186			for _, inst := range rc.InstanceNames() {
187				rcByInstance[inst] = rc
188			}
189		}
190	
191		for i := range statuses {
192			hcfg, ok := cfg.Hosts[statuses[i].Host]
193			if !ok {
194				continue
195			}
196			rc := rcByInstance[statuses[i].Instance]
197			if rc == nil {
198				continue
199			}
200			exp := expectedGitHubRunnerOS(hcfg.OS)
201			key := scopeKey{rc.Scope(), rc.ScopeTarget()}
202			for _, gr := range scopeRunners[key] {
203				if gr.Name != statuses[i].Instance {
204					continue
205				}
206				if exp != "" && gr.OS != "" && !strings.EqualFold(gr.OS, exp) {
207					continue
208				}
209				statuses[i].Remote = gr.Status
210				statuses[i].Busy = gr.Busy
211				break
212			}
213		}
214	}
215	
216	func (m *Manager) CleanupOffline(cfg *config.Config) (int, error) {
217		type scopeKey struct{ scope, target string }
