20			}
21			if hcfg.OS != "" && hcfg.Arch != "" {
22				continue
23			}
24			if w != nil {
25				fmt.Fprintf(w, "Detecting OS/arch for host %s (%s)...\n", name, hcfg.Addr)
26			}
27			h, err := ConnectHost(name, hcfg)
28			if err != nil {
29				return fmt.Errorf("auto-detect %s: %w", name, err)
30			}
31			if hcfg.OS == "" {
32				detectedOS, err := host.DetectOS(h)
33				if err != nil {
34					h.Close()
35					return fmt.Errorf("auto-detect OS for %s: %w", name, err)
36				}
37				hcfg.OS = detectedOS
38			}
39			if hcfg.Arch == "" {
40				detectedArch, err := host.DetectArch(h)
41				if err != nil {
42					h.Close()
43					return fmt.Errorf("auto-detect arch for %s: %w", name, err)
44				}
45				hcfg.Arch = detectedArch
46			}
47			h.Close()
48			cfg.Hosts[name] = hcfg
49			if w != nil {
50				fmt.Fprintf(w, "  %s: detected os=%s arch=%s\n", name, hcfg.OS, hcfg.Arch)
51			}
52		}
53		return nil
