12	// NativeRunnerConfigPresent reports whether the remote instance directory contains
13	// a configured runner (.runner), matching the check used by setup and doctor.
14	func NativeRunnerConfigPresent(h *host.Host, instanceName string) (bool, error) {
15		dir := h.RunnerDir(instanceName)
16		if h.OS == "windows" {
17			out, err := h.RunShell(fmt.Sprintf(
18				"%s; if (Test-Path (Join-Path $runnerDir '.runner')) { Write-Output 'yes' } else { Write-Output 'no' }",
19				windowsRunnerDirAssignment(h, "runnerDir", instanceName),
20			))
21			if err != nil {
22				return false, err
23			}
24			return strings.TrimSpace(out) == "yes", nil
25		}
26		out, err := h.Run(fmt.Sprintf("test -f %s/.runner && echo yes || echo no", dir))
27		if err != nil {
28			return false, err
29		}
30		return strings.TrimSpace(out) == "yes", nil
31	}
32	
33	func runnerTarballURL(version, osName, arch string) string {
34		switch osName {
35		case "darwin":
36			return fmt.Sprintf(
37				"https://github.com/actions/runner/releases/download/v%s/actions-runner-osx-%s-%s.tar.gz",
38				version, arch, version,
39			)
40		case "linux":
41			return fmt.Sprintf(
42				"https://github.com/actions/runner/releases/download/v%s/actions-runner-linux-%s-%s.tar.gz",
43				version, arch, version,
44			)
45		case "windows":
46			a := arch
47			if a == "amd64" {
48				a = "x64"
49			}
50			return fmt.Sprintf(
51				"https://github.com/actions/runner/releases/download/v%s/actions-runner-win-%s-%s.zip",
52				version, a, version,
53			)
54		}
55		return ""
56	}
57	
58	func archForGitHub(arch string) string {
59		switch arch {
60		case "amd64":
61			return "x64"
62		case "arm64":
63			return "arm64"
64		}
65		return arch
66	}
67	
68	func powerShellSingleQuoted(s string) string {
69		return "'" + strings.ReplaceAll(s, "'", "''") + "'"
70	}
71	
72	func windowsRunnerDirAssignment(h *host.Host, varName, instanceName string) string {
73		return fmt.Sprintf("$%s = %s", varName, h.RunnerDirPS(instanceName))
74	}
75	
76	func windowsNativeInstallScript(h *host.Host, instanceName, version, url string) string {
77		zipName := fmt.Sprintf("actions-runner-%s.zip", version)
78		return strings.Join([]string{
79			windowsRunnerDirAssignment(h, "runnerDir", instanceName),
80			"New-Item -ItemType Directory -Force -Path $runnerDir | Out-Null",
81			fmt.Sprintf("$zip = Join-Path %s %s", h.TempDirPS(), powerShellSingleQuoted(zipName)),
82			fmt.Sprintf("if (-not (Test-Path $zip)) { Invoke-WebRequest -Uri %s -OutFile $zip }", powerShellSingleQuoted(url)),
83			"Expand-Archive -Path $zip -DestinationPath $runnerDir -Force",
84		}, "; ")
85	}
86	
87	// nativeConfigURL returns the --url value for config.sh / config.cmd.
88	func nativeConfigURL(rc config.RunnerConfig) string {
89		if rc.Org != "" {
90			return "https://github.com/" + rc.Org
91		}
92		return "https://github.com/" + rc.Repo
93	}
94	
95	func windowsNativeConfigScript(h *host.Host, rc config.RunnerConfig, instanceName, regToken string) string {
96		labels := strings.Join(rc.EffectiveLabels(h.OS, h.Arch), ",")
97		cmd := fmt.Sprintf(
98			"& .\\config.cmd --unattended --url %s --token %s --name %s --labels %s --work '_work' --replace",
99			powerShellSingleQuoted(nativeConfigURL(rc)),
100			powerShellSingleQuoted(regToken),
101			powerShellSingleQuoted(instanceName),
102			powerShellSingleQuoted(labels),
103		)
104		if rc.Group != "" {
105			cmd += fmt.Sprintf(" --runnergroup %s", powerShellSingleQuoted(rc.Group))
106		}
107		if rc.Ephemeral {
108			cmd += " --ephemeral"
109		}
110		return strings.Join([]string{
111			windowsRunnerDirAssignment(h, "runnerDir", instanceName),
112			"Set-Location -Path $runnerDir",
113			cmd,
114		}, "; ")
115	}
116	
117	// staleRegistrationMsg is the substring the Actions runner writes to its log when the
118	// server-side registration has been deleted (auto-pruned after inactivity).
119	const staleRegistrationMsg = "runner registration has been deleted from the server"
120	
121	func windowsNativeStartScript(h *host.Host, instanceName string) string {
122		// Win32-OpenSSH tears down the session job on disconnect, killing Start-Process children.
123		// Win32_Process.Create starts outside that job so the listener survives after gh sr closes SSH.
124		parts := []string{
125			windowsRunnerDirAssignment(h, "runnerDir", instanceName) + "; ",
126			`$pidFile = Join-Path $runnerDir '.runner_pid'; `,
127			`$logFile = Join-Path $runnerDir 'runner.log'; `,
128			`if (Test-Path $pidFile) { $existingPid = Get-Content $pidFile; try { Get-Process -Id $existingPid -EA Stop | Out-Null; Write-Host 'already running'; exit 0 } catch {} }; `,
129			`$cmdArg = 'cd /d "' + $runnerDir + '" && run.cmd > "' + $logFile + '" 2>&1'; `,
130			`$fullLine = 'cmd.exe /c ' + $cmdArg; `,
131			`$cim = Invoke-CimMethod -ClassName Win32_Process -MethodName Create -Arguments @{ CommandLine = $fullLine; CurrentDirectory = $runnerDir }; `,
132			`if ($cim.ReturnValue -ne 0) { Write-Host ('Win32_Process.Create failed: ' + $cim.ReturnValue); exit 1 }; `,
133			`$cim.ProcessId | Out-File -FilePath $pidFile -NoNewline; `,
134			`Write-Host ('started PID ' + $cim.ProcessId)`,
135		}
136		return strings.Join(parts, "")
137	}
138	
139	// windowsCheckStaleRegistration returns a PowerShell snippet that waits briefly for the
140	// runner process to either stay alive (healthy) or exit, then checks runner.log for the
141	// stale-registration message. It writes "stale" to stdout if detected, "ok" otherwise.
142	func windowsCheckStaleRegistration(h *host.Host, instanceName string) string {
143		return fmt.Sprintf(
144			"%s; $pidFile = Join-Path $runnerDir '.runner_pid'; "+
145				"$logFile = Join-Path $runnerDir 'runner.log'; "+
146				"Start-Sleep -Seconds 5; "+
147				"$pid = Get-Content $pidFile -EA SilentlyContinue; "+
148				"$alive = $false; if ($pid) { try { Get-Process -Id $pid -EA Stop | Out-Null; $alive = $true } catch {} }; "+
149				"if ($alive) { Write-Host 'ok' } "+
150				"elseif ((Test-Path $logFile) -and (Select-String -Path $logFile -Pattern %s -Quiet)) { Write-Host 'stale' } "+
151				"else { Write-Host 'ok' }",
152			windowsRunnerDirAssignment(h, "runnerDir", instanceName),
153			powerShellSingleQuoted(staleRegistrationMsg),
154		)
155	}
156	
157	// windowsDeleteRunnerConfig removes the .runner file so setupNative will re-configure.
158	func windowsDeleteRunnerConfig(h *host.Host, instanceName string) string {
159		return fmt.Sprintf(
160			"%s; Remove-Item -Force (Join-Path $runnerDir '.runner') -EA SilentlyContinue; "+
161				"Remove-Item -Force (Join-Path $runnerDir '.credentials') -EA SilentlyContinue; "+
162				"Remove-Item -Force (Join-Path $runnerDir '.credentials_rsaparams') -EA SilentlyContinue",
163			windowsRunnerDirAssignment(h, "runnerDir", instanceName),
164		)
165	}
