167	func (m *Manager) setupNative(h *host.Host, rc config.RunnerConfig) error {
168		version, err := m.GitHub.GetLatestRunnerVersion()
169		if err != nil {
170			return err
171		}
172	
173		ghArch := archForGitHub(h.Arch)
174		url := runnerTarballURL(version, h.OS, ghArch)
175		if url == "" {
176			return fmt.Errorf("unsupported OS/arch: %s/%s", h.OS, h.Arch)
177		}
178	
179		for _, name := range rc.InstanceNames() {
180			dir := h.RunnerDir(name)
181	
182			installed, _ := NativeRunnerConfigPresent(h, name)
183			if installed {
184				fmt.Fprintf(m.out(), "  %s: already installed, skipping\n", name)
185				continue
186			}
187	
188			fmt.Fprintf(m.out(), "  %s: installing runner v%s...\n", name, version)
189	
190			if h.OS == "linux" {
191				installDepsCmd := linuxElevatePrelude + `
192					if ! command -v curl >/dev/null 2>&1 || ! command -v tar >/dev/null 2>&1; then
193						if command -v apt-get >/dev/null 2>&1; then $SUDO apt-get update && $SUDO apt-get install -y curl tar;
194						elif command -v yum >/dev/null 2>&1; then $SUDO yum install -y curl tar;
195						elif command -v apk >/dev/null 2>&1; then $SUDO apk add curl tar;
196						fi
197					fi
198				`
199				if _, err := h.Run(installDepsCmd); err != nil {
200					fmt.Fprintf(m.out(), "  %s: warning: failed to ensure curl/tar are installed: %v\n", name, err)
201				}
202			}
203	
204			if h.OS == "windows" {
205				if _, err := h.RunShell(windowsNativeInstallScript(h, name, version, url)); err != nil {
206					return fmt.Errorf("installing runner on Windows: %w", err)
207				}
208			} else {
209				tarball := fmt.Sprintf("%s/ghsr-runner-%s-%s.tar.gz", h.TempDir(), name, version)
210				cmds := fmt.Sprintf(
211					"mkdir -p %s && cd %s && tarball=%s && rm -f \"$tarball\" && "+
212						"curl -fSL --retry 3 --retry-delay 2 -o \"$tarball\" '%s' && "+
213						"tar xzf \"$tarball\" && rm -f \"$tarball\"",
214					dir, dir, tarball, url,
215				)
216				if _, err := h.Run(cmds); err != nil {
217					return fmt.Errorf("installing runner: %w", err)
218				}
219			}
220	
221			if h.OS == "linux" {
222				depsCmd := fmt.Sprintf(
223					"cd %s && %s && $SUDO ./bin/installdependencies.sh",
224					dir, strings.TrimSpace(linuxElevatePrelude),
225				)
226				if _, err := h.Run(depsCmd); err != nil {
227					fmt.Fprintf(m.out(), "  %s: warning: failed to install runner dependencies: %v\n", name, err)
228				}
229			}
230	
231			regToken, err := m.GitHub.GetRegistrationTokenScoped(rc.Scope(), rc.ScopeTarget())
232			if err != nil {
233				return err
234			}
235	
236			labels := strings.Join(rc.EffectiveLabels(h.OS, h.Arch), ",")
237	
238			if h.OS == "windows" {
239				if _, err := h.RunShell(windowsNativeConfigScript(h, rc, name, regToken)); err != nil {
240					return fmt.Errorf("configuring runner on Windows: %w", err)
241				}
242			} else {
243				configURL := nativeConfigURL(rc)
244				configCmd := fmt.Sprintf(
245					"cd %s && ./config.sh --unattended --url '%s' --token '%s' --name '%s' --labels '%s' --work '_work' --replace",
246					dir, configURL, regToken, name, labels,
247				)
248				if rc.Group != "" {
249					configCmd += fmt.Sprintf(" --runnergroup '%s'", rc.Group)
250				}
251				if rc.Ephemeral {
252					configCmd += " --ephemeral"
253				}
254				if _, err := h.Run(configCmd); err != nil {
255					return fmt.Errorf("configuring runner: %w", err)
256				}
257			}
258	
259			fmt.Fprintf(m.out(), "  %s: configured\n", name)
260		}
261	
262		// For agentic runners, install gh-aw CLI on the host.
263		// gh-aw (GitHub Agentic Workflows) uses Docker on the host for AWF sandbox containers.
264		if rc.IsAgentic() && h.OS == "linux" {
265			fmt.Fprintf(m.out(), "  %s: installing gh-aw CLI for agentic profile...\n", rc.Name)
266			installGHAWCmd := `if [ -d ~/.local/share/gh/extensions/gh-aw ]; then
267				echo "gh-aw already installed"
268			else
269				curl -sL https://raw.githubusercontent.com/github/gh-aw/main/install-gh-aw.sh | bash
270			fi`
271			out, err := h.Run(installGHAWCmd)
272			if err != nil {
273				fmt.Fprintf(m.out(), "  %s: warning: failed to install gh-aw CLI: %v\n", rc.Name, err)
274			} else {
275				fmt.Fprintf(m.out(), "  %s: gh-aw CLI installed\n", rc.Name)
276				if out != "" {
277					fmt.Fprintf(m.out(), "  %s: gh-aw: %s\n", rc.Name, strings.TrimSpace(out))
278				}
279			}
280		}
281	
282		return nil
283	}
284	
285	func (m *Manager) startNative(h *host.Host, rc config.RunnerConfig, instanceName string) error {
286		return m.startNativeOnce(h, rc, instanceName, true)
287	}
288	
289	// startNativeOnce starts the runner and optionally detects a stale registration.
290	// When retryOnStale is true and the runner exits immediately with the stale-registration
291	// message, it clears local credentials, re-runs setupNative, and retries once.
292	func (m *Manager) startNativeOnce(h *host.Host, rc config.RunnerConfig, instanceName string, retryOnStale bool) error {
293		dir := h.RunnerDir(instanceName)
294	
295		ok, err := NativeRunnerConfigPresent(h, instanceName)
296		if err != nil {
297			return fmt.Errorf("checking runner install at %s: %w", dir, err)
298		}
299		if !ok {
300			fmt.Fprintf(m.out(), "  %s: not installed, running setup...\n", instanceName)
301			if setupErr := m.setupNative(h, rc); setupErr != nil {
302				return fmt.Errorf("auto-setup for %s: %w", instanceName, setupErr)
303			}
304		}
305	
306		if h.OS == "windows" {
307			out, err := h.RunShell(windowsNativeStartScript(h, instanceName))
308			if err != nil {
309				return err
310			}
311			fmt.Fprintf(m.out(), "  %s: %s\n", instanceName, strings.TrimSpace(out))
312	
313			if retryOnStale {
314				checkOut, _ := h.RunShell(windowsCheckStaleRegistration(h, instanceName))
315				if strings.TrimSpace(checkOut) == "stale" {
316					return m.handleStaleRegistration(h, rc, instanceName)
317				}
318			}
319			return nil
320		}
321	
322		// Unix (Linux / macOS)
323		cmd := fmt.Sprintf(
324			`cd %s && pid_file=".runner_pid" && `+
325				`if [ -f "$pid_file" ] && kill -0 "$(cat "$pid_file")" 2>/dev/null; then echo "already running"; exit 0; fi && `+
326				`nohup ./run.sh > runner.log 2>&1 & echo $! > "$pid_file" && echo "started PID $!"`,
327			dir,
328		)
329		out, err := h.Run(cmd)
330		if err != nil {
331			return err
332		}
333		fmt.Fprintf(m.out(), "  %s: %s\n", instanceName, strings.TrimSpace(out))
334	
335		if retryOnStale {
336			checkCmd := fmt.Sprintf(
337				`cd %s && sleep 5 && pid=$(cat .runner_pid 2>/dev/null) && `+
338					`if [ -n "$pid" ] && kill -0 "$pid" 2>/dev/null; then echo ok; `+
339					`elif grep -q %q runner.log 2>/dev/null; then echo stale; `+
340					`else echo ok; fi`,
341				dir, staleRegistrationMsg,
342			)
343			checkOut, _ := h.Run(checkCmd)
344			if strings.TrimSpace(checkOut) == "stale" {
345				return m.handleStaleRegistration(h, rc, instanceName)
346			}
347		}
348		return nil
349	}
350	
351	func (m *Manager) handleStaleRegistration(h *host.Host, rc config.RunnerConfig, instanceName string) error {
352		fmt.Fprintf(m.out(), "  %s: registration expired on GitHub, re-configuring...\n", instanceName)
353		dir := h.RunnerDir(instanceName)
354	
355		if h.OS == "windows" {
356			h.RunShell(windowsDeleteRunnerConfig(h, instanceName))
357		} else {
358			h.Run(fmt.Sprintf("rm -f %s/.runner %s/.credentials %s/.credentials_rsaparams", dir, dir, dir))
359		}
360	
361		if err := m.setupNative(h, rc); err != nil {
362			return fmt.Errorf("re-configuring after stale registration: %w", err)
363		}
364	
365		return m.startNativeOnce(h, rc, instanceName, false)
366	}
367	
368	func (m *Manager) stopNative(h *host.Host, instanceName string) error {
369		dir := h.RunnerDir(instanceName)
370	
371		if h.OS == "windows" {
372			cmd := fmt.Sprintf(
373				"%s; $pidFile = Join-Path $runnerDir '.runner_pid'; "+
374					"if (-not (Test-Path $pidFile)) { Write-Host 'not running'; exit 0 }; "+
375					"$p = (Get-Content $pidFile | Select-Object -First 1).Trim(); "+
376					"$null = & taskkill.exe /PID $p /T /F 2>&1; "+
377					"if ($LASTEXITCODE -eq 0) { Write-Host 'stopped' } else { Write-Host 'not running' }; "+
378					"Remove-Item $pidFile -Force -EA SilentlyContinue",
379				windowsRunnerDirAssignment(h, "runnerDir", instanceName),
380			)
381			out, err := h.RunShell(cmd)
382			if err != nil {
383				return err
384			}
385			fmt.Fprintf(m.out(), "  %s: %s\n", instanceName, strings.TrimSpace(out))
386			return nil
387		}
388	
389		cmd := fmt.Sprintf(
390			`cd %s && pid_file=".runner_pid" && `+
391				`if [ ! -f "$pid_file" ]; then echo "not running"; exit 0; fi && `+
392				`pid=$(cat "$pid_file") && `+
393				`if ! kill -0 "$pid" 2>/dev/null; then echo "not running"; rm -f "$pid_file"; exit 0; fi && `+
394				`kill "$pid" && `+
395				`for i in $(seq 1 10); do kill -0 "$pid" 2>/dev/null || break; sleep 1; done && `+
396				`kill -0 "$pid" 2>/dev/null && kill -9 "$pid" 2>/dev/null; `+
397				`rm -f "$pid_file" && echo "stopped"`,
398			dir,
399		)
400		out, err := h.Run(cmd)
401		if err != nil {
402			return err
403		}
404		fmt.Fprintf(m.out(), "  %s: %s\n", instanceName, strings.TrimSpace(out))
405		return nil
406	}
407	
408	func (m *Manager) removeNative(h *host.Host, rc config.RunnerConfig, instanceName string) error {
409		dir := h.RunnerDir(instanceName)
410	
411		_ = m.stopNative(h, instanceName)
412	
413		removeToken, err := m.GitHub.GetRemovalTokenScoped(rc.Scope(), rc.ScopeTarget())
414		if err != nil {
415			fmt.Fprintf(m.out(), "  %s: warning: could not get removal token: %v\n", instanceName, err)
416		} else {
417			if h.OS == "windows" {
418				cmd := fmt.Sprintf(
419					"%s; Set-Location -Path $runnerDir; & .\\config.cmd remove --token %s",
420					windowsRunnerDirAssignment(h, "runnerDir", instanceName),
421					powerShellSingleQuoted(removeToken),
422				)
423				h.RunShell(cmd)
424			} else {
425				cmd := fmt.Sprintf("cd %s && ./config.sh remove --token '%s'", dir, removeToken)
426				h.Run(cmd)
427			}
428			fmt.Fprintf(m.out(), "  %s: deregistered\n", instanceName)
429		}
430	
431		if h.OS == "windows" {
432			h.RunShell(fmt.Sprintf("%s; Remove-Item -Recurse -Force $runnerDir", windowsRunnerDirAssignment(h, "runnerDir", instanceName)))
433		} else {
434			h.Run(fmt.Sprintf("rm -rf %s", dir))
435		}
436	
437		fmt.Fprintf(m.out(), "  %s: removed\n", instanceName)
438		return nil
439	}
440	
441	func (m *Manager) statusNative(h *host.Host, instanceName string) string {
442		dir := h.RunnerDir(instanceName)
443	
444		if kind, err := autostart.Detect(h, instanceName); err == nil && kind != autostart.KindNone {
445			active, err := autostart.IsServiceActive(h, instanceName, kind)
446			if err != nil {
447				return "unknown"
448			}
449			if active {
450				return "running"
451			}
452			return "stopped"
453		}
454	
455		if h.OS == "windows" {
456			cmd := fmt.Sprintf(
457				"%s; if (-not (Test-Path (Join-Path $runnerDir '.runner'))) { Write-Host 'not installed'; exit 0 }; "+
458					"$pidFile = Join-Path $runnerDir '.runner_pid'; "+
459					"if (-not (Test-Path $pidFile)) { Write-Host 'stopped'; exit 0 }; "+
460					"$p = Get-Content $pidFile; "+
461					"try { Get-Process -Id $p -EA Stop | Out-Null; Write-Host 'running' } catch { Write-Host 'stopped' }",
462				windowsRunnerDirAssignment(h, "runnerDir", instanceName),
463			)
464			out, _ := h.RunShell(cmd)
465			return strings.TrimSpace(out)
466		}
467	
468		cmd := fmt.Sprintf(
469			`d="%s" && `+
470				`if [ ! -f "$d/.runner" ]; then echo "not installed"; exit 0; fi && `+
471				`pid_file="$d/.runner_pid" && `+
472				`if [ ! -f "$pid_file" ]; then echo "stopped"; exit 0; fi && `+
473				`pid=$(cat "$pid_file") && `+
474				`if kill -0 "$pid" 2>/dev/null; then echo "running"; else echo "stopped"; fi`,
475			dir,
476		)
477		out, err := h.Run(cmd)
478		if err != nil {
479			return "unknown"
480		}
481		return strings.TrimSpace(out)
482	}
483	
484	func (m *Manager) logsNative(h *host.Host, instanceName string) (string, error) {
485		dir := h.RunnerDir(instanceName)
486	
487		if h.OS == "windows" {
488			cmd := fmt.Sprintf(
489				"%s; $logFile = Join-Path $runnerDir 'runner.log'; "+
490					"$diagDir = Join-Path $runnerDir '_diag'; "+
491					"$tailMain = { if (Test-Path $logFile) { $lines = @(Get-Content -LiteralPath $logFile -Tail 50 -EA SilentlyContinue); "+
492					"$j = [string]::Join([Environment]::NewLine, $lines); "+
493					"if ($lines.Count -gt 0 -and ($j -match '\\S')) { $j } else { $null } } else { $null } }; "+
494					"$main = & $tailMain; "+
495					"if ($null -ne $main) { Write-Output $main } "+
496					"elseif (Test-Path $diagDir) { "+
497					"$latest = Get-ChildItem -Path $diagDir -Filter *.log -File -EA SilentlyContinue | Sort-Object LastWriteTime -Descending | Select-Object -First 1; "+
498					"if ($latest) { Write-Output ('--- _diag/' + $latest.Name + ' (last 50 lines) ---'); Get-Content -LiteralPath $latest.FullName -Tail 50 } "+
499					"else { Write-Output 'no logs found' } } "+
500					"else { Write-Output 'no logs found' }",
501				windowsRunnerDirAssignment(h, "runnerDir", instanceName),
502			)
503			return h.RunShell(cmd)
504		}
505	
506		cmd := fmt.Sprintf("tail -50 %s/runner.log 2>/dev/null || echo 'no logs found'", dir)
507		return h.Run(cmd)
508	}
509

