362			}
363		}
364		if rc.Name == nameArg {
365			names := rc.InstanceNames()
366			if len(names) != 1 {
367				return "", fmt.Errorf("runner %q has %d instances; specify one of: %s", rc.Name, len(names), strings.Join(names, ", "))
368			}
