374	// FindRunnerForLogs resolves a runner by base or instance name. If hostFilter is non-empty, only that host's runner block matches.
375	// Returns an error when nothing matches or when multiple hosts match the same name without a host filter.
376	func (c *Config) FindRunnerForLogs(nameArg, hostFilter string) (*RunnerConfig, error) {
377		var matches []*RunnerConfig
378		seen := map[*RunnerConfig]bool{}
379		for i := range c.Runners {
380			r := &c.Runners[i]
381			if hostFilter != "" && r.Host != hostFilter {
382				continue
383			}
384			matched := false
385			if r.Name == nameArg {
386				matched = true
387			} else {
388				for _, inst := range r.InstanceNames() {
389					if inst == nameArg {
390						matched = true
391						break
392					}
393				}
394			}
395			if matched && !seen[r] {
396				seen[r] = true
397				matches = append(matches, r)
398			}
399		}
400		if len(matches) == 0 {
401			if hostFilter != "" {
402				return nil, fmt.Errorf("runner %q not found for host %q", nameArg, hostFilter)
403			}
404			return nil, fmt.Errorf("runner %q not found in config", nameArg)
405		}
406		if len(matches) > 1 {
407			hosts := make([]string, 0, len(matches))
408			for _, r := range matches {
409				hosts = append(hosts, r.Host)
410			}
411			return nil, fmt.Errorf("runner %q matches multiple hosts %v; specify --host", nameArg, hosts)
412		}
413		return matches[0], nil
414	}
