416	// FilterRunners returns runners matching optional host, repo, and/or explicit runner/instance names.
417	func FilterRunners(cfg *Config, hostFilter, repoFilter string, nameArgs []string) []RunnerConfig {
418		runners := cfg.Runners
419	
420		if hostFilter != "" {
421			var filtered []RunnerConfig
422			for _, r := range runners {
423				if r.Host == hostFilter {
424					filtered = append(filtered, r)
425				}
426			}
427			runners = filtered
428		}
429	
430		if repoFilter != "" {
431			var filtered []RunnerConfig
432			for _, r := range runners {
433				if r.Repo == repoFilter {
434					filtered = append(filtered, r)
435				}
436			}
437			runners = filtered
438		}
439	
440		if len(nameArgs) > 0 {
441			nameSet := map[string]bool{}
442			for _, a := range nameArgs {
443				nameSet[a] = true
444			}
445			var filtered []RunnerConfig
446			for _, r := range runners {
447				if nameSet[r.Name] {
448					filtered = append(filtered, r)
449					continue
450				}
451				for _, inst := range r.InstanceNames() {
452					if nameSet[inst] {
453						filtered = append(filtered, r)
454						break
455					}
456				}
457			}
458			runners = filtered
459		}
460	
461		return runners
462	}
